sql.where:

    AND (
        c.title LIKE CONCAT('%', #{keyword}, '%')
        OR EXISTS (
            SELECT 1
              FROM CONTENT_HASHTAG cht
              JOIN HASHTAG h ON h.id = cht.hashtag_id
             WHERE cht.content_id = c.id
               AND h.name LIKE CONCAT('%', #{keyword}, '%')
        )
    )


    AND c.type = #{type}


    AND c.status = #{status}


    AND c.channel_id = #{channelId}

AND (#{churchId} IS NULL OR ch.church_id = #{churchId})
